function collectReviewKnowledge(){
  const map=new Map();
  (data?.exams||[]).forEach(e=>(e.sets||[]).forEach(s=>{const st=arr(e.id,s.id),list=s.questions||[];list.forEach((q,i)=>{const wrong=st.graded&&(st.wrong||[]).includes(i),unsure=!!st.confidence?.[i];if(!wrong&&!unsure)return;const chapter=q.chapter||"ç« ن¸چوکژ",category=reviewCategoryFromQuestion(q),theme=themeLabelFromQuestion(q),k=`${chapter}|${category}|${theme}`;if(!map.has(k))map.set(k,{key:k,chapter,category,theme,wrongCount:0,unsureCount:0,lastWrongAt:"",questions:[]});const x=map.get(k);if(wrong)x.wrongCount++;if(unsure)x.unsureCount++;const at=st.gradedAt||st.updated||e.date||"";if(wrong&&at>x.lastWrongAt)x.lastWrongAt=at;x.questions.push({e,s,q,index:i,userAnswer:st.answers?.[i]||"",wrong,unsure,at});})}));
  return [...map.values()];
}
