function filteredManageExams(){
  let q=(manageSearch||"").trim().toLowerCase();
  let list=[...data.exams].filter(e=>{
    if(e._systemEmpty)return false;
    let customFlag=isCustomExam(e.id),cat=examCategory(e),sample=isSampleExam(e);
    if(manageFilter==="custom"&&!customFlag)return false;
    if(manageFilter==="official"&&customFlag)return false;
    if(manageFilter==="one_by_one"&&cat!=="one_by_one")return false;
    if(manageFilter==="exam_style"&&cat!=="exam_style")return false;
    if(manageFilter==="practice60"&&cat!=="practice60")return false;
    if(manageFilter==="sample"&&!sample)return false;
    if(q&&!examSearchText(e).includes(q))return false;
    return true;
  });
  list.sort((a,b)=>{
    if(manageSort==="old")return String(a.date||"").localeCompare(String(b.date||""));
    if(manageSort==="title")return String(a.title||"").localeCompare(String(b.title||""),'ja');
    if(manageSort==="questions")return examQuestionCount(b)-examQuestionCount(a);
    return String(b.date||"").localeCompare(String(a.date||""));
  });
  return list;
}
