document.addEventListener("click",e=>{const ch=e.target.closest("[data-analysis-chapter]");if(ch){openKnowledgeReview();knowledgeReviewView={level:"categories",chapter:ch.dataset.analysisChapter,category:"",theme:"",scroll:0};renderKnowledgeReview();return}const th=e.target.closest("[data-analysis-theme]");if(th){const x=collectReviewKnowledge().find(v=>v.key===th.dataset.analysisTheme);if(!x)return;openKnowledgeReview();knowledgeReviewView={level:"detail",chapter:x.chapter,category:x.category,theme:x.key,scroll:0};renderKnowledgeReview();}});
if(localStorage.getItem(LOGIN)==="ok")boot();
if("serviceWorker" in navigator){
  window.addEventListener("load",async()=>{
    try{
      const reg=await navigator.serviceWorker.register("./service-worker.js?v=13.5.1",{updateViaCache:"none"});
      await reg.update();
      if(reg.waiting){reg.waiting.postMessage({type:"SKIP_WAITING"});}
      navigator.serviceWorker.addEventListener("controllerchange",()=>{if(!window.__swReloaded){window.__swReloaded=true;location.reload();}});
    }catch(e){console.warn("Service Worker registration failed",e)}
  });
}
